import json
import hashlib
import re
from dataclasses import dataclass, field
from pathlib import Path
from datetime import datetime, timezone
from typing import Optional

@dataclass
class PromptVersion:
    template_id: str
    version: str               # semver, e.g. "1.2.0"
    template: str              # the actual prompt text with {{variable}} placeholders
    variables: list[str]       # declared input variables
    model_constraints: dict    # e.g. {"max_tokens": 1024, "temperature": 0.0}
    status: str = "draft"      # draft | review | published | deprecated
    safety_review: dict = field(default_factory=dict)
    domain_review: dict = field(default_factory=dict)
    ab_experiment_id: Optional[str] = None
    rollback_target: Optional[str] = None
    created_at: str = ""
    author: str = ""

    def __post_init__(self):
        if not self.created_at:
            self.created_at = datetime.now(timezone.utc).isoformat()

    def sha256(self) -> str:
        return hashlib.sha256(self.template.encode()).hexdigest()[:16]

    def render(self, **kwargs) -> str:
        result = self.template
        for var in self.variables:
            if var not in kwargs:
                raise ValueError(f"Missing required variable: {var}")
            result = result.replace("{{" + var + "}}", str(kwargs[var]))
        undeclared = re.findall(r"\{\{(\w+)\}\}", result)
        if undeclared:
            raise ValueError(f"Template contains undeclared variables: {undeclared}")
        return result

class PromptRegistry:
    def __init__(self, registry_dir: Path):
        self._dir = registry_dir
        self._dir.mkdir(parents=True, exist_ok=True)

    def _path(self, template_id: str, version: str) -> Path:
        return self._dir / template_id / f"{version}.json"

    def publish(self, pv: PromptVersion) -> None:
        if pv.status not in ("review", "published"):
            raise ValueError(f"Cannot publish template with status: {pv.status}")
        p = self._path(pv.template_id, pv.version)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_text(json.dumps(pv.__dict__, indent=2))
        current_path = self._dir / pv.template_id / "current.json"
        current_path.write_text(json.dumps({"version": pv.version, "sha256": pv.sha256()}))

    def load(self, template_id: str, version: str = "current") -> PromptVersion:
        if version == "current":
            current = json.loads((self._dir / template_id / "current.json").read_text())
            version = current["version"]
        data = json.loads(self._path(template_id, version).read_text())
        return PromptVersion(**data)

    def rollback(self, template_id: str, target_version: str) -> None:
        pv = self.load(template_id, target_version)
        current_path = self._dir / template_id / "current.json"
        current_path.write_text(json.dumps({"version": pv.version, "sha256": pv.sha256()}))
        print(f"Rolled back {template_id} to version {target_version}")

    def list_versions(self, template_id: str) -> list[str]:
        template_dir = self._dir / template_id
        if not template_dir.exists():
            return []
        return sorted(
            p.stem for p in template_dir.glob("*.json") if p.stem != "current",
            key=lambda v: [int(x) for x in v.split(".")]
        )
